struct FieldCondition
    key::String
    match::Union{Nothing,Match}
    range::Union{Nothing,Range}
    geo_bounding_box::Union{Nothing,GeoBoundingBox}
    geo_radius::Union{Nothing,GeoRadius}
    values_count::Union{Nothing,ValuesCount}
    geo_polygon::Union{Nothing,GeoPolygon}
    datetime_range::Union{Nothing,DatetimeRange}
    is_empty::Bool
    is_null::Bool
end
PB.default_values(::Type{FieldCondition}) = (;key = "", match = nothing, range = nothing, geo_bounding_box = nothing, geo_radius = nothing, values_count = nothing, geo_polygon = nothing, datetime_range = nothing, is_empty = false, is_null = false)
PB.field_numbers(::Type{FieldCondition}) = (;key = 1, match = 2, range = 3, geo_bounding_box = 4, geo_radius = 5, values_count = 6, geo_polygon = 7, datetime_range = 8, is_empty = 9, is_null = 10)

function PB.decode(d::PB.AbstractProtoDecoder, ::Type{<:FieldCondition})
    key = ""
    match = Ref{Union{Nothing,Match}}(nothing)
    range = Ref{Union{Nothing,Range}}(nothing)
    geo_bounding_box = Ref{Union{Nothing,GeoBoundingBox}}(nothing)
    geo_radius = Ref{Union{Nothing,GeoRadius}}(nothing)
    values_count = Ref{Union{Nothing,ValuesCount}}(nothing)
    geo_polygon = Ref{Union{Nothing,GeoPolygon}}(nothing)
    datetime_range = Ref{Union{Nothing,DatetimeRange}}(nothing)
    is_empty = false
    is_null = false
    while !PB.message_done(d)
        field_number, wire_type = PB.decode_tag(d)
        if field_number == 1
            key = PB.decode(d, String)
        elseif field_number == 2
            PB.decode!(d, match)
        elseif field_number == 3
            PB.decode!(d, range)
        elseif field_number == 4
            PB.decode!(d, geo_bounding_box)
        elseif field_number == 5
            PB.decode!(d, geo_radius)
        elseif field_number == 6
            PB.decode!(d, values_count)
        elseif field_number == 7
            PB.decode!(d, geo_polygon)
        elseif field_number == 8
            PB.decode!(d, datetime_range)
        elseif field_number == 9
            is_empty = PB.decode(d, Bool)
        elseif field_number == 10
            is_null = PB.decode(d, Bool)
        else
            Base.skip(d, wire_type)
        end
    end
    return FieldCondition(key, match[], range[], geo_bounding_box[], geo_radius[], values_count[], geo_polygon[], datetime_range[], is_empty, is_null)
end

function PB.encode(e::PB.AbstractProtoEncoder, x::FieldCondition)
    initpos = position(e.io)
    !isempty(x.key) && PB.encode(e, 1, x.key)
    !isnothing(x.match) && PB.encode(e, 2, x.match)
    !isnothing(x.range) && PB.encode(e, 3, x.range)
    !isnothing(x.geo_bounding_box) && PB.encode(e, 4, x.geo_bounding_box)
    !isnothing(x.geo_radius) && PB.encode(e, 5, x.geo_radius)
    !isnothing(x.values_count) && PB.encode(e, 6, x.values_count)
    !isnothing(x.geo_polygon) && PB.encode(e, 7, x.geo_polygon)
    !isnothing(x.datetime_range) && PB.encode(e, 8, x.datetime_range)
    x.is_empty != false && PB.encode(e, 9, x.is_empty)
    x.is_null != false && PB.encode(e, 10, x.is_null)
    return position(e.io) - initpos
end
function PB._encoded_size(x::FieldCondition)
    encoded_size = 0
    !isempty(x.key) && (encoded_size += PB._encoded_size(x.key, 1))
    !isnothing(x.match) && (encoded_size += PB._encoded_size(x.match, 2))
    !isnothing(x.range) && (encoded_size += PB._encoded_size(x.range, 3))
    !isnothing(x.geo_bounding_box) && (encoded_size += PB._encoded_size(x.geo_bounding_box, 4))
    !isnothing(x.geo_radius) && (encoded_size += PB._encoded_size(x.geo_radius, 5))
    !isnothing(x.values_count) && (encoded_size += PB._encoded_size(x.values_count, 6))
    !isnothing(x.geo_polygon) && (encoded_size += PB._encoded_size(x.geo_polygon, 7))
    !isnothing(x.datetime_range) && (encoded_size += PB._encoded_size(x.datetime_range, 8))
    x.is_empty != false && (encoded_size += PB._encoded_size(x.is_empty, 9))
    x.is_null != false && (encoded_size += PB._encoded_size(x.is_null, 10))
    return encoded_size
end

