const Condition = var"##Stub#Condition"{var"##Stub#Filter"}
PB.oneof_field_types(::Type{Condition}) = (;
    condition_one_of = (;field=FieldCondition, is_empty=IsEmptyCondition, has_id=HasIdCondition, filter=Filter, is_null=IsNullCondition, nested=NestedCondition, has_vector=HasVectorCondition),
)
PB.default_values(::Type{Condition}) = (;field = nothing, is_empty = nothing, has_id = nothing, filter = nothing, is_null = nothing, nested = nothing, has_vector = nothing)
PB.field_numbers(::Type{Condition}) = (;field = 1, is_empty = 2, has_id = 3, filter = 4, is_null = 5, nested = 6, has_vector = 7)

function PB.decode(d::PB.AbstractProtoDecoder, ::Type{<:Condition})
    condition_one_of = nothing
    while !PB.message_done(d)
        field_number, wire_type = PB.decode_tag(d)
        if field_number == 1
            condition_one_of = OneOf(:field, PB.decode(d, Ref{FieldCondition}))
        elseif field_number == 2
            condition_one_of = OneOf(:is_empty, PB.decode(d, Ref{IsEmptyCondition}))
        elseif field_number == 3
            condition_one_of = OneOf(:has_id, PB.decode(d, Ref{HasIdCondition}))
        elseif field_number == 4
            condition_one_of = OneOf(:filter, PB.decode(d, Ref{Filter}))
        elseif field_number == 5
            condition_one_of = OneOf(:is_null, PB.decode(d, Ref{IsNullCondition}))
        elseif field_number == 6
            condition_one_of = OneOf(:nested, PB.decode(d, Ref{NestedCondition}))
        elseif field_number == 7
            condition_one_of = OneOf(:has_vector, PB.decode(d, Ref{HasVectorCondition}))
        else
            Base.skip(d, wire_type)
        end
    end
    return Condition(condition_one_of)
end

function PB.encode(e::PB.AbstractProtoEncoder, x::Condition)
    initpos = position(e.io)
    if isnothing(x.condition_one_of);
    elseif x.condition_one_of.name === :field
        PB.encode(e, 1, x.condition_one_of[]::FieldCondition)
    elseif x.condition_one_of.name === :is_empty
        PB.encode(e, 2, x.condition_one_of[]::IsEmptyCondition)
    elseif x.condition_one_of.name === :has_id
        PB.encode(e, 3, x.condition_one_of[]::HasIdCondition)
    elseif x.condition_one_of.name === :filter
        PB.encode(e, 4, x.condition_one_of[]::Filter)
    elseif x.condition_one_of.name === :is_null
        PB.encode(e, 5, x.condition_one_of[]::IsNullCondition)
    elseif x.condition_one_of.name === :nested
        PB.encode(e, 6, x.condition_one_of[]::NestedCondition)
    elseif x.condition_one_of.name === :has_vector
        PB.encode(e, 7, x.condition_one_of[]::HasVectorCondition)
    end
    return position(e.io) - initpos
end
function PB._encoded_size(x::Condition)
    encoded_size = 0
    if isnothing(x.condition_one_of);
    elseif x.condition_one_of.name === :field
        encoded_size += PB._encoded_size(x.condition_one_of[]::FieldCondition, 1)
    elseif x.condition_one_of.name === :is_empty
        encoded_size += PB._encoded_size(x.condition_one_of[]::IsEmptyCondition, 2)
    elseif x.condition_one_of.name === :has_id
        encoded_size += PB._encoded_size(x.condition_one_of[]::HasIdCondition, 3)
    elseif x.condition_one_of.name === :filter
        encoded_size += PB._encoded_size(x.condition_one_of[]::Filter, 4)
    elseif x.condition_one_of.name === :is_null
        encoded_size += PB._encoded_size(x.condition_one_of[]::IsNullCondition, 5)
    elseif x.condition_one_of.name === :nested
        encoded_size += PB._encoded_size(x.condition_one_of[]::NestedCondition, 6)
    elseif x.condition_one_of.name === :has_vector
        encoded_size += PB._encoded_size(x.condition_one_of[]::HasVectorCondition, 7)
    end
    return encoded_size
end

